def range_summary(nums):
    if not nums: return ''
    prev_num = nums[0]
    result = []

    for num in nums:
        if num == prev_num + 1:
            prev_num = num
        else:
            if prev_num != num and (prev_num != nums[0] or num != nums[-1]):
                result.append(f'{prev_num}' if prev_num < num - 1 else f'{prev_num}-{num}')
            else:
                result.append(str(prev_num))
            prev_num = num

    return ','.join(result)
